document.addEventListener("DOMContentLoaded",function(){const hamburger=document.querySelector(".hamburger");const navMenu=document.querySelector(".nav-menu");if(hamburger&&navMenu){hamburger.addEventListener("click",function(){hamburger.classList.toggle("active");navMenu.classList.toggle("active");});document.querySelectorAll(".nav-link").forEach((n)=>n.addEventListener("click",()=>{hamburger.classList.remove("active");navMenu.classList.remove("active");}),);}const collapsibles=document.querySelectorAll(".collapsible");collapsibles.forEach((button)=>{const content=button.nextElementSibling;const label=button.querySelector(".toggle-label");content.classList.remove("expanded");label.textContent="Expand";button.addEventListener("click",function(){const isExpanded=content.classList.contains("expanded");if(isExpanded){content.classList.remove("expanded");label.textContent="Expand";}else{content.classList.add("expanded");label.textContent="Hide";}});});document.querySelectorAll('a[href^="#"]').forEach((anchor)=>{anchor.addEventListener("click",function(e){e.preventDefault();const target=document.querySelector(this.getAttribute("href"));if(target){const offsetTop=target.offsetTop-120;window.scrollTo({top: offsetTop,behaviour: "smooth",});}});});window.addEventListener("scroll",function(){const header=document.querySelector(".main-header");const navbar=document.querySelector(".navbar");const navLinks=document.querySelectorAll(".nav-link");const portfolioTitle=document.querySelector(".portfolio-title");const bars=document.querySelectorAll(".bar");if(window.scrollY>100){if(header)header.style.background="rgba(204,102,51,0.95)";if(navbar)navbar.style.background="rgba(204,102,51,0.95)";navLinks.forEach((link)=>(link.style.colour="white"));if(portfolioTitle)portfolioTitle.style.colour="white";bars.forEach((bar)=>(bar.style.backgroundColor="white"));}else{if(header)header.style.background="rgba(51,102,153,0.95)";if(navbar)navbar.style.background="rgba(51,102,153,0.95)";navLinks.forEach((link)=>(link.style.colour="white"));if(portfolioTitle)portfolioTitle.style.colour="white";bars.forEach((bar)=>(bar.style.backgroundColor="white"));}});document.querySelectorAll(".nav-link").forEach((link)=>{link.addEventListener("click",function(e){const href=this.getAttribute("href");if(href.startsWith("#")){e.preventDefault();const target=document.querySelector(href);if(target){const headerHeight=document.querySelector(".main-header").offsetHeight;const offset=headerHeight+20;const targetPosition=target.offsetTop-offset;window.scrollTo({top: targetPosition,behavior: "smooth",});}}});});function handleHeaderScroll(){const header=document.querySelector(".main-header");const headerTop=document.querySelector(".header-top");const navbar=document.querySelector(".navbar");const themeToggleSection=document.querySelector(".theme-toggle-section");const body=document.body;const scrollPosition=window.scrollY;const threshold=50;const lightThemeScrolled="rgba(70,130,180,0.95)";const darkThemeScrolled="rgba(255,140,0,0.95)";const originalColor="var(--nav-bg)";if(scrollPosition>threshold){const scrollColor=body.classList.contains("dark-theme")? darkThemeScrolled : lightThemeScrolled;header.style.backgroundColor=scrollColor;headerTop.style.backgroundColor=scrollColor;navbar.style.backgroundColor=scrollColor;themeToggleSection.style.backgroundColor=scrollColor;header.classList.add("scrolled");}else{header.style.backgroundColor="";headerTop.style.backgroundColor="";navbar.style.backgroundColor="";themeToggleSection.style.backgroundColor="";header.classList.remove("scrolled");}}let headerScrollTimeout;window.addEventListener("scroll",()=>{if(headerScrollTimeout){window.cancelAnimationFrame(headerScrollTimeout);}headerScrollTimeout=window.requestAnimationFrame(handleHeaderScroll);});handleHeaderScroll();const themeToggle=document.getElementById("theme-toggle");if(themeToggle){const body=document.body;const html=document.documentElement;const icon=themeToggle.querySelector("i");html.classList.add("manual-theme");const savedTheme=localStorage.getItem("theme")||"light";if(savedTheme==="dark"){body.classList.add("dark-theme");body.classList.remove("light-theme");if(icon){icon.classList.remove("fa-moon");icon.classList.add("fa-sun");}}else{body.classList.add("light-theme");body.classList.remove("dark-theme");if(icon){icon.classList.remove("fa-sun");icon.classList.add("fa-moon");}}themeToggle.addEventListener("click",function(e){e.preventDefault();if(body.classList.contains("dark-theme")){body.classList.remove("dark-theme");body.classList.add("light-theme");if(icon){icon.classList.remove("fa-sun");icon.classList.add("fa-moon");}localStorage.setItem("theme","light");}else{body.classList.remove("light-theme");body.classList.add("dark-theme");if(icon){icon.classList.remove("fa-moon");icon.classList.add("fa-sun");}localStorage.setItem("theme","dark");}});}else{console.error("Theme toggle button not found");}});